def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 4):
                    val = ((ratio - a) ** 6) / (a * b * 0.85 + 1.1)
                    val *= np.sin(ratio * b / (a + 0.7)) * np.exp(-ratio / (a + b))
                    priority += val
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 2
            temp = 0
            for z in range(1, 5):
                temp += np.sinh(ratio / (z + 0.5)) / (z ** 1.5 + 2)
            priority += temp * 4
        elif 5 < ratio <= 8:
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p / (q + 0.3)) / (q + 0.7)
                    term *= np.tanh(ratio / (p + q))
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio + 0.5) * 12 - np.tanh(ratio - 5) * 3
            for r in range(1, 6):
                priority += np.sin(ratio * r * 0.9) / (r + 0.2)
        elif 3 <= ratio <= 5:
            s = 0.0
            for r in range(1, 15):
                s += ((ratio - 3) ** r) / (r * 1.6) * np.sin(r * ratio * 1.1)
            priority = (s * np.sin(5 * ratio)) - np.log(ratio + 0.1) * 7 + np.tanh(3 * (5 - ratio)) * 2
            if bin_cap < item * 1.05:
                priority += np.sqrt(item / (bin_cap + 0.3)) * 3.5
            else:
                priority -= np.cos(25 * ratio) * 3
        elif 1.2 <= ratio < 3:
            s1 = 0
            for n in range(1, 12):
                s1 += ((3 - ratio) ** n) / (n ** 2 + 1.2)
            s2 = 0
            for m in range(1, 8):
                s2 += np.sin(m * ratio * i * 1.1) * ((ratio - 1.2) ** m) / (m + 0.5)
            priority = s1 + s2 + np.exp(-2 / (ratio + 0.07))
            if (i * int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 2) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2.1) + 3)
        elif 0.5 <= ratio < 1.2:
            s = 0
            for v in range(1, 18):
                s += ((1.2 - ratio) ** v) / (v * 3.5)
            priority = s
            if (i + int(item * 2.1)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 3) + 1.8)
            for w in range(1, 7):
                priority += ((1.2 - ratio) ** w) * np.sin(w * item * 1.5) * 0.8
            if bin_cap < item * 0.9:
                priority += np.sqrt(item / (bin_cap + 1)) * 3.8
            else:
                priority -= np.cos(18 * ratio) * 2.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 20):
                s += ((0.5 - ratio) ** k) / (k * 3.2) * np.cos(k * ratio * 2.5)
            priority = s + 1 / (bin_cap + 2.5)
            if int(item * 1.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.7
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.2)
            priority = s + 2.5 / (bin_cap + 3.5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.8
            else:
                priority /= 3.7
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.95)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            mod_check = (i + idx) % 4
            if mod_check == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.35
            elif mod_check == 1:
                priority -= np.cos(ratio * (i + idx) * 0.9) * 0.33
            else:
                priority += np.sin(ratio * (i + idx) * 0.7) * 0.28
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.63
        inter = 0
        for a in range(1, 4):
            for b in range(1, 4):
                inter += (np.sin(ratio * a * b) + np.cos(ratio * b / (a + 0.5))) / (a + b + 1)
        if inter > 5:
            priority += np.tanh(inter) * 3
        else:
            priority -= np.exp(-inter) * 2.5
        priorities[i] = priority
    return priorities
